class Solution:
    def maximumLength(self, s: str) -> int:
        n = len(s)
        max_len = -1
        for char in set(s):
            count = 0
            curr_len = 0
            lengths = []
            for i in range(n):
                if s[i] == char:
                    curr_len += 1
                else:
                    if curr_len > 0:
                        lengths.append(curr_len)
                    curr_len = 0
            if curr_len > 0:
                lengths.append(curr_len)
            lengths.sort(reverse=True)
            if len(lengths) >= 3:
                max_len = max(max_len, lengths[2])
            if len(lengths) >= 1:
                max_len = max(max_len, lengths[0] - 2)
        return max_len

